from agno import Agent
from vex import verify
import json

@verify(
    schema={
        "type": "object",
        "properties": {
            "denial_code": {"type": "string", "pattern": "^[A-Z]{2}-\\d{3}$"},
            "explanation": {"type": "string", "minLength": 50},
            "appeal_instructions": {"type": "string"}
        },
        "required": ["denial_code", "explanation"]
    },
    rules=["explanation must be business-related, not personal characteristics"]
)
def claims_agent(run):
    agent = Agent(name="ClaimsProcessor", model="gpt-4o")
    response = agent.run(run)
    return json.loads(response)

claim_result = claims_agent("Process claim ID 12345 with medical records")

from agno import MultimodalAgent
from vex import verify

@verify(
    rules=[
        "no demographic assumptions from images",
        "audio transcript redacts PII",
        "premium_change justified by policy terms"
    ],
    pii_redaction=True
)
def policy_review_agent(run):
    agent = MultimodalAgent(
        model="gpt-4o",
        image_tools=True,
        audio_tools=True
    )
    return agent.run(run)

review = policy_review_agent("Review renewal with customer photo ID and call recording")
